/* jsPDF AutoTable Plugin - Professional Table Support */
/* Uses CDN with proper promise-based loading */

if (!window.jspdfAutotablePromise) {
  window.jspdfAutotablePromise = new Promise((resolve, reject) => {
    // First, wait for jsPDF to be available
    var checkJsPDF = setInterval(() => {
      if (window.jspdf && window.jspdf.jsPDF) {
        clearInterval(checkJsPDF);
        
        // Now load autotable
        console.log('[jsPDF AutoTable] Loading from CDN...');
        var script = document.createElement('script');
        script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.5.28/jspdf.plugin.autotable.min.js';
        script.async = true;
        
        var timeout = setTimeout(() => {
          reject(new Error('jsPDF AutoTable CDN load timeout'));
        }, 10000);
        
        script.onload = function() {
          clearTimeout(timeout);
          console.log('[jsPDF AutoTable] Successfully loaded from CDN');
          resolve(true);
        };
        
        script.onerror = function() {
          clearTimeout(timeout);
          console.warn('[jsPDF AutoTable] CDN load failed, will use basic table support');
          resolve(false);
        };
        
        document.head.appendChild(script);
      }
    }, 100);
    
    // Timeout waiting for jsPDF
    var jspdfTimeout = setTimeout(() => {
      clearInterval(checkJsPDF);
      reject(new Error('Timeout waiting for jsPDF'));
    }, 15000);
  });
}
